import SwiftUI

@MainActor final class GameEngine: ObservableObject { @Published private(set) var state: GameState = .idle; @Published private(set) var progress = 0.0; @Published private(set) var secondsLeft = 0; @Published private(set) var result = ScoreBreakdown(score:0, stars:0); private(set) var challenge: ChallengeKind = .beam; func prepare(_ kind: ChallengeKind) { challenge = kind; progress = 0; secondsLeft = Int(kind.seconds); state = .intro }; func scan() { state = .scanning }; func startNow() { state = .running }; func tick(input: ChallengeInput) { switch ChallengeRuleEvaluator.eval(kind: challenge, input: input) { case .running(let p): progress = p.clamped(); case .won: finish(didWin:true, progress:1, penalty:input.hits); case .lost(let reason): state = .failed(reason); finish(didWin:false, progress:progress, penalty:input.hits) } }; func finish(didWin: Bool, progress: Double, penalty: Int) { result = ScoreCalculator.score(accuracy: didWin ? 1 : 0.4, progress: progress, penalty: penalty, didWin: didWin); state = didWin ? .success : .complete }; func reset() { state = .idle } }
